import useExploreCourts from "../features/courts/hooks/useExploreCourts";
import { useNavigate } from "react-router-dom";
import "./Explore.css";
import "../components/CourtCard.css";

// Your 6 real padel court images embedded directly
const PADEL_IMAGES = [
  "data:image/webp;base64,",
  "data:image/webp;base64,",
  "data:image/webp;base64,",
  "data:image/webp;base64,",
  "data:image/webp;base64,",
  "data:image/webp;base64,"
];

function getCourtImage(court, index) {
  if (court.imageUrl && court.imageUrl.trim() !== "") return court.imageUrl;
  return PADEL_IMAGES[index % PADEL_IMAGES.length];
}

function Stars({ rating }) {
  if (!rating) return <span className="court-no-rating">No ratings yet</span>;
  return (
    <span className="court-stars">
      {[1, 2, 3, 4, 5].map((n) => (
        <span key={n} style={{ color: n <= Math.round(rating) ? "#f97316" : "#d1d5db" }}>★</span>
      ))}
      <span className="court-rating-num">{Number(rating).toFixed(1)}</span>
    </span>
  );
}

function CourtCard({ court, index }) {
  const navigate = useNavigate();
  const imageSrc = getCourtImage(court, index);

  return (
    <div className="court-card">
      <div className="court-card-image">
        <img src={imageSrc} alt={court.name} />
      </div>
      <div className="court-card-body">
        <h3 className="court-title">{court.name || "Court Name"}</h3>
        <p className="court-location">📍 {court.location || "Unknown location"}</p>
        <div className="court-rating-row">
          <Stars rating={court.avgRating} />
          {court.reviewCount > 0 && (
            <span className="court-review-count">({court.reviewCount} reviews)</span>
          )}
        </div>
        <div className="court-card-footer">
          <span className="court-price">
            {court.pricePerHour ? `${court.pricePerHour} EGP` : "N/A"}
          </span>
          <button className="court-btn" onClick={() => navigate(`/courts/${court._id}`)}>
            View Details
          </button>
        </div>
      </div>
    </div>
  );
}

export default function Explore() {
  const { courts, loading, error, filters, handleFilterChange, handleSearch, handleClear } =
    useExploreCourts();

  return (
    <div className="explore-page">
      <div className="explore-header">
        <h1>Explore Courts</h1>
        <p>Find and book your perfect padel court</p>
      </div>
      <form onSubmit={handleSearch} className="explore-filter-bar">
        <input name="name" value={filters.name} onChange={handleFilterChange} placeholder="Search by name" className="explore-filter-input" />
        <input name="location" value={filters.location} onChange={handleFilterChange} placeholder="Location" className="explore-filter-input" />
        <input name="price" value={filters.price} onChange={handleFilterChange} placeholder="Max price" className="explore-filter-input" />
        <div className="explore-actions">
          <button type="submit" className="btn primary">Search</button>
          <button type="button" onClick={handleClear} className="btn secondary">Clear</button>
        </div>
      </form>
      {loading && <div className="state-box"><p>Loading courts...</p></div>}
      {error && <div className="error-box"><p>{error}</p></div>}
      <div className="explore-grid">
        {courts.map((court, index) => (
          <CourtCard key={court._id} court={court} index={index} />
        ))}
      </div>
      {!loading && courts.length === 0 && (
        <div className="state-box"><p>No courts found</p></div>
      )}
    </div>
  );
}
